import{_ as a,o as t,c as o,ag as r}from"./chunks/framework.BYehg5q7.js";const m=JSON.parse('{"title":"Compare Dates","description":"","frontmatter":{},"headers":[],"relativePath":"guide/compare-dates.md","filePath":"guide/compare-dates.md","lastUpdated":1771855656000}'),i={name:"guide/compare-dates.md"};function n(s,e,l,h,d,c){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="compare-dates" tabindex="-1">Compare Dates <a class="header-anchor" href="#compare-dates" aria-label="Permalink to &quot;Compare Dates&quot;">​</a></h1><p>The Compare view lets you select any two lab dates and see how every marker changed between them. It is useful for evaluating the effect of a diet change, a new supplement protocol, a medication, or any other intervention you tracked.</p><h2 id="opening-the-compare-view" tabindex="-1">Opening the Compare View <a class="header-anchor" href="#opening-the-compare-view" aria-label="Permalink to &quot;Opening the Compare View&quot;">​</a></h2><p>Navigate to the Compare section using the sidebar. You will see two date pickers — one for each date you want to compare.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You need at least two lab entries on different dates before the Compare view has anything to show.</p></div><h2 id="reading-the-comparison" tabindex="-1">Reading the Comparison <a class="header-anchor" href="#reading-the-comparison" aria-label="Permalink to &quot;Reading the Comparison&quot;">​</a></h2><p>Once you select two dates, every marker that has a value on either date appears in the comparison table. For each marker you can see:</p><ul><li>The value on the first (earlier) date</li><li>The value on the second (later) date</li><li>The direction and magnitude of the change</li><li>Whether each value is within the reference range</li></ul><p>Markers with no data on one of the selected dates still appear, showing the available value alongside a blank for the missing date.</p><h2 id="status-colors" tabindex="-1">Status Colors <a class="header-anchor" href="#status-colors" aria-label="Permalink to &quot;Status Colors&quot;">​</a></h2><p>Status colors follow the same convention as the rest of the app: green for normal, red for high, blue for low. This lets you quickly see whether a marker moved into or out of range between the two dates.</p><h2 id="tips-for-effective-comparison" tabindex="-1">Tips for Effective Comparison <a class="header-anchor" href="#tips-for-effective-comparison" aria-label="Permalink to &quot;Tips for Effective Comparison&quot;">​</a></h2><ul><li><strong>Before and after</strong> — Pick a date just before starting an intervention and a date several months later to measure impact.</li><li><strong>Year-over-year</strong> — Compare the same season across different years to account for seasonal variation in markers like vitamin D.</li><li><strong>Narrowing the range</strong> — Use the date range filter in the header alongside the Compare view. Only dates within the active range appear in the date pickers.</li></ul>',13)])])}const u=a(i,[["render",n]]);export{m as __pageData,u as default};
